def validate(args, output):
    root_arr, key = args
    # collect all values in the original tree (BFS level-order)
    def bfs_values(arr):
        vals = set()
        for v in arr:
            if v is not None:
                vals.add(v)
        return vals
    original_vals = bfs_values(root_arr)
    expected_vals = original_vals - {key}
    # validate output tree: collect inorder and check BST property
    def inorder(node):
        if node is None:
            return []
        return inorder(node.left) + [node.val] + inorder(node.right)
    def is_bst(node, lo=float('-inf'), hi=float('inf')):
        if node is None:
            return True
        if not (lo < node.val < hi):
            return False
        return is_bst(node.left, lo, node.val) and is_bst(node.right, node.val, hi)
    if output is None:
        return len(expected_vals) == 0
    if not is_bst(output):
        return False
    got_vals = set(inorder(output))
    return got_vals == expected_vals

judge.validator_javascript:
function validate(args, output) {
    const [rootArr, key] = args;
    function bfsValues(arr) {
        const s = new Set();
        for (const v of arr) if (v !== null) s.add(v);
        return s;
    }
    const originalVals = bfsValues(rootArr);
    originalVals.delete(key);
    const expectedVals = originalVals;
    function inorder(node) {
        if (!node) return [];
        return [...inorder(node.left), node.val, ...inorder(node.right)];
    }
    function isBst(node, lo = -Infinity, hi = Infinity) {
        if (!node) return true;
        if (node.val <= lo || node.val >= hi) return false;
        return isBst(node.left, lo, node.val) && isBst(node.right, node.val, hi);
    }
    if (!output) return expectedVals.size === 0;
    if (!isBst(output)) return false;
    const gotVals = new Set(inorder(output));
    if (gotVals.size !== expectedVals.size) return false;
    for (const v of expectedVals) if (!gotVals.has(v)) return false;
    return true;
}

