def gen(rng, size):
    n = max(1, min(size, 200))
    vals = list(rng.sample(range(-100000, 100001), n))
    # build level-order array by inserting into a BST
    root_arr = []
    def insert(arr, val):
        if not arr:
            arr.append(val)
            return
        idx = 0
        while True:
            if arr[idx] is None:
                arr[idx] = val
                return
            if val < arr[idx]:
                left = 2 * idx + 1
                while len(arr) <= left:
                    arr.append(None)
                idx = left
            else:
                right = 2 * idx + 2
                while len(arr) <= right:
                    arr.append(None)
                idx = right
    for v in vals:
        insert(root_arr, v)
    while root_arr and root_arr[-1] is None:
        root_arr.pop()
    key = rng.choice(vals)
    return [root_arr, key]

