class Solution:
    def deleteNode(self, root, key):
        if root is None:
            return None
        if key < root.val:
            root.left = self.deleteNode(root.left, key)
        elif key > root.val:
            root.right = self.deleteNode(root.right, key)
        else:
            # found: handle 0/1/2 children
            if root.left is None:
                return root.right
            if root.right is None:
                return root.left
            # two children: find minimum in right subtree
            m = root.right
            while m.left:
                m = m.left
            root.val = m.val
            root.right = self.deleteNode(root.right, m.val)
        return root

